UPDATE articles SET content = '[{"id":"k1","type":"heading2","text":"📋 Личное меню"},{"id":"k2","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/e804f5e1915c4945a4dd34d3595243fa.png","caption":"Интерфейс личного меню"},{"id":"k3","type":"paragraph","text":"Данное меню доступно по чат-команде `/m` или `/fast`. В открывшемся окне вы найдёте всё что вам нужно, без необходимости прописывать какие-либо чат-команды."},{"id":"k4","type":"divider"},{"id":"k5","type":"heading2","text":"⌨️ Бинд на кнопку"},{"id":"k6","type":"paragraph","text":"Для более быстрого доступа к меню можно установить бинд — привязку к клавише. Откройте консоль клавишей `F1` и введите команду:"},{"id":"k7","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/c0599bb5c42341a89f4b0816107fdc89.png","caption":"Консоль с биндом"},{"id":"k8","type":"tip","icon":"Пример команды","text":"`bind m chat.say /m`\n\nГде **m** — это клавиша, на которую удобно открывать меню. Готово! Теперь при нажатии **M** (в английской раскладке) будет открываться личное меню."}]' WHERE id = 9;

UPDATE articles SET content = '[{"id":"l1","type":"paragraph","text":"Виртуальные карьеры добывают за вас полезные компоненты: серу, камень, МВК, карьерное топливо, кастомные руды и полезные минералы."},{"id":"l2","type":"divider"},{"id":"l3","type":"step","stepNum":1,"text":"Перейдите в **личное меню** `/m` и кликните по вкладке **«Виртуальные карьеры»**"},{"id":"l4","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/57dda68e83b8472bb3d45f89d0014c03.jpg","caption":"Вкладка Виртуальных карьеров в личном меню"},{"id":"l5","type":"step","stepNum":2,"text":"Для установки карьера или нефтекачки вам потребуется **Геологический заряд**"},{"id":"l6","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/cbfcbe2d4e9b486b98d397b0a7a4d3c3.png","caption":"Геологический заряд"},{"id":"l7","type":"step","stepNum":3,"text":"Нажмите кнопку **«Добавить +»**"},{"id":"l8","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/5f805411e2224aa980dcccc2d5037222.png","caption":"Кнопка добавить"},{"id":"l9","type":"step","stepNum":4,"text":"Найдите месторождение которое вас устроит по выпавшим ресурсам. **1 нажатие на «Искать» = 1 геологический заряд**"},{"id":"l10","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/dd86ca9466814a8b9697cb5b0b10f226.png","caption":"Поиск месторождения"},{"id":"l11","type":"step","stepNum":5,"text":"После выбора месторождения — нажмите кнопку «Установить»"},{"id":"l12","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/18377b6924934a7096367d31e0b35ab0.png","caption":"Кнопка установки карьера"},{"id":"l13","type":"warning","icon":"Важно про слоты!","text":"При установке карьера его хранилище рассчитано всего на **3 слота**. Если добываемых предметов больше 3 — нужно **улучшать карьер**, иначе он будет постоянно отключаться!"},{"id":"l14","type":"tip","icon":"Запуск карьера","text":"Для работы карьера нужно **карьерное топливо** — поместите его в бак и запустите карьер. Нефтекачки работают по такому же принципу."}]' WHERE id = 10;
